const PROCESSING_FEE = 5;

type Item = { type: string };
type QuoteStep = { op: "quote"; items: Item[] };
type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
type StepResult = { premium: number };
type ScenarioResult = { results: StepResult[] };

const BASE_PRICES: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

const basePriceOf = (item: Item): number => BASE_PRICES[item.type] ?? 0;

const THREE_RUNE_BLOCK_PRICE = 60;

const isThreeRuneBlock = (items: Item[]): boolean =>
  items.length === 3 && items.every((i) => i.type === "rune");

const sumBasePrices = (items: Item[]): number => {
  if (isThreeRuneBlock(items)) return THREE_RUNE_BLOCK_PRICE;
  return items.reduce((sum, item) => sum + basePriceOf(item), 0);
};

const quotePremium = (items: Item[]): number =>
  sumBasePrices(items) + PROCESSING_FEE;

const runStep = (step: QuoteStep): StepResult => ({
  premium: quotePremium(step.items),
});

export const runScenario = (input: Scenario): ScenarioResult => ({
  results: input.steps.map(runStep),
});

