const basePriceOf = (item: Item): number => BASE_PRICES[item.type] ?? 0;

const CURSED_SURCHARGE_RATE = 0.5;
const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
const HIGH_ENCHANTMENT_THRESHOLD = 5;

const isCursed = (item: Item): boolean => item.cursed === true;
const isHighlyEnchanted = (item: Item): boolean =>
  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;

const surchargeRate = (item: Item): number =>
  (isCursed(item) ? CURSED_SURCHARGE_RATE : 0) +
  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE_RATE : 0);

const itemPremium = (item: Item): number => {
  const base = basePriceOf(item);
  return base + base * surchargeRate(item);
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const BLOCK_SIZE = 3;
const BLOCK_PRICE = 60;

const groupByType = (items: Item[]): Map<string, Item[]> => {
  const groups = new Map<string, Item[]>();
  for (const item of items) {
    const existing = groups.get(item.type) ?? [];
    existing.push(item);
    groups.set(item.type, existing);
  }
  return groups;
};

const groupPremium = (type: string, members: Item[]): number => {
  if (COMPONENT_TYPES.has(type) && members.length === BLOCK_SIZE) return BLOCK_PRICE;
  return members.reduce((sum, item) => sum + itemPremium(item), 0);
};

const itemsSubtotal = (items: Item[]): number =>
  Array.from(groupByType(items)).reduce(
    (total, [type, members]) => total + groupPremium(type, members),
    0,
  );

const quotePremium = (items: Item[]): number =>
  itemsSubtotal(items) + PROCESSING_FEE;

const runStep = (step: QuoteStep): StepResult => ({
  premium: quotePremium(step.items),
