import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // --- Simplest cases ---
  it("empty item list → premium 5 G (only the processing fee)", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(out.results[0]).toEqual({ premium: 5 });
  });

  // --- Base premiums for main items (each + 5 G fee) ---
  it("quote a plain sword → premium 115 G (100 base + 10 first-insurance + 5 fee)", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword" }] }],
    });
    expect(out.results[0]).toEqual({ premium: 115 });
  });
  it("quote a plain amulet → premium 71 G (60 base + 6 first-insurance + 5 fee)", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "amulet" }] }],
    });
    expect(out.results[0]).toEqual({ premium: 71 });
  });
  it("quote a plain staff → premium 93 G (80 base + 8 first-insurance + 5 fee)", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "staff" }] }],
    });
    expect(out.results[0]).toEqual({ premium: 93 });
  });
  it("quote a plain potion → premium 49 G (40 base + 4 first-insurance + 5 fee)", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "potion" }] }],
    });
    expect(out.results[0]).toEqual({ premium: 49 });
  });

  // --- Components and blocks ---
  it("quote 2 runes → 50 G base premium (55 with fee)", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
    });
    expect(out.results[0]).toEqual({ premium: 55 });
  });
  it("quote 3 runes → 60 G base premium block (65 with fee)", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }],
        },
      ],
    });
    expect(out.results[0]).toEqual({ premium: 65 });
  });
  it("quote 4 runes → 100 G base premium, no block (105 with fee)", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
          ],
        },
      ],
    });
    expect(out.results[0]).toEqual({ premium: 105 });
  });
  it("quote 7 runes → 175 G base premium (180 with fee)", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: Array.from({ length: 7 }, () => ({ type: "rune" })),
        },
      ],
    });
    expect(out.results[0]).toEqual({ premium: 180 });
  });
  it("quote 2 runes + 1 moonstone → 75 G base premium (alike = same type)", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }],
        },
      ],
    });
    expect(out.results[0]).toEqual({ premium: 80 });
  });
  it("quote 3 runes + 3 moonstones → 120 G base premium (two separate blocks)", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
            { type: "moonstone" },
            { type: "moonstone" },
            { type: "moonstone" },
          ],
        },
      ],
    });
    expect(out.results[0]).toEqual({ premium: 125 });
  });

  // --- Item-specific modifiers ---
  it("cursed sword adds 50% surcharge on its base premium → 155 G", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", cursed: true }] }],
    });
    expect(out.results[0]).toEqual({ premium: 155 });
  });
  it("sword with enchantment 5 adds 30% surcharge → 135 G", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", enchantment: 5 }] }],
    });
    expect(out.results[0]).toEqual({ premium: 135 });
  });
  it("sword with enchantment 4 has no high-enchantment surcharge → 105 G", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", enchantment: 4 }] }],
    });
    expect(out.results[0]).toEqual({ premium: 105 });
  });
  it("cursed sword with enchantment 5 has both surcharges → 185 G", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", cursed: true, enchantment: 5 }],
        },
      ],
    });
    expect(out.results[0]).toEqual({ premium: 185 });
  });

  // --- Policy-wide modifiers ---
  it("long-standing customer (≥ 2 years) gets 20% loyalty discount on policy base", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 3 },
      steps: [{ op: "quote", items: [{ type: "sword" }] }],
    });
    expect(out.results[0]).toEqual({ premium: 85 });
  });
  it("customer with exactly 2 years gets loyalty discount", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 2 },
      steps: [{ op: "quote", items: [{ type: "sword" }] }],
    });
    expect(out.results[0]).toEqual({ premium: 85 });
  });
  it("first insurance carries 10% initial assessment surcharge on policy base", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword" }] }],
    });
    expect(out.results[0]).toEqual({ premium: 115 });
  });
  it.todo("second contract gets 15% follow-up discount on policy base");

  // --- Modifier scope on multi-item policies ---
  it.todo("cursed sword + plain amulet → 100 + 60 base + 50 curse + 5 fee = 215 G");

  // --- Rounding ---
  it.todo("premium yielding 197.5 G rounds up to 198 G (MHPCO favor)");

  // --- Integration examples ---
  it.todo("newcomer with cursed sword (0 years, no prev contract, ench 3) → 165 G");
  it.todo("long-standing customer's second cursed enchanted sword (3 yrs, ench 7) → 160 G");

  // --- Claim: basic standard reimbursement ---
  it.todo("regular sword damage 500 G → payout 400 G (500 − 100 deductible)");
  it.todo("rune damage 200 G → payout 100 G (no special clause)");

  // --- Claim: special clauses ---
  it.todo("dragon-material sword ench 9, damage 1000 G → payout 400 G (50% then deductible)");
  it.todo("dragon-material sword ench 5, damage 800 G → payout 700 G (full minus deductible)");
  it.todo("steel sword ench 9, damage 1000 G → payout 400 G (50% then deductible)");
  it.todo("dragon-material sword exactly ench 8, damage 1000 G → payout 400 G");

  // --- Claim: per-damage-event deductible ---
  it.todo("dragon attack on sword (500) and amulet (300) → payout 600 G (deductible per item)");

  // --- Claim: rounding ---
  it.todo("payout yielding 350.5 G rounds down to 350 G (MHPCO favor)");

  // --- Claim: cap ---
  it.todo("policy of sword and amulet → insurance sum 1600 G, cap 3200 G");
  it.todo("cursed sword → cap 2000 G (based on unmodified insurance value)");
  it.todo("sword + 3 runes (block) → insurance sum 1750 G (block affects premium only)");
  it.todo("sword 1500 G claim then 1500 G claim → payouts 1400, 600; cap 600 then 0");

  // --- Multiple items of same type ---
  it.todo("policy with two swords → insurance sum 2000 G, cap 4000 G");
  it.todo("two sword damages on two-sword policy → each gets own deductible");
  it.todo("damages array has more entries of a type than policy covers → CLI errors");

  // --- Edge cases / error handling ---
  it.todo("quote with unknown item type → CLI errors non-zero, stderr message, no results");
  it.todo("claim references item not in policy → CLI errors");
  it.todo("claim damage amount negative → CLI errors");
});

