const PROCESSING_FEE = 5;

type Item = { type: string; cursed?: boolean; enchantment?: number };
type Customer = { yearsWithMHPCO: number };
type QuoteStep = { op: "quote"; items: Item[] };
type Damage = { itemType: string; amount: number };
type Incident = { cause: string; damages: Damage[] };
type ClaimStep = { op: "claim"; policy: number; incident: Incident };
type Step = QuoteStep | ClaimStep;
type Scenario = { customer: Customer; steps: Step[] };
type QuoteResult = { premium: number };
type ClaimResult = { payout: number; remainingCap: number };
type StepResult = QuoteResult | ClaimResult;
type ScenarioResult = { results: StepResult[] };

type ItemSpec = { basePrice: number; insuranceValue: number };

const ITEM_CATALOG: Record<string, ItemSpec> = {
  sword: { basePrice: 100, insuranceValue: 1000 },
  amulet: { basePrice: 60, insuranceValue: 600 },
  staff: { basePrice: 80, insuranceValue: 800 },
  potion: { basePrice: 40, insuranceValue: 400 },
  rune: { basePrice: 25, insuranceValue: 250 },
  moonstone: { basePrice: 25, insuranceValue: 250 },
};

const specOf = (item: Item): ItemSpec | undefined => ITEM_CATALOG[item.type];

const basePriceOf = (item: Item): number => specOf(item)?.basePrice ?? 0;

const CURSED_SURCHARGE_RATE = 0.5;
const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
const HIGH_ENCHANTMENT_THRESHOLD = 5;

const isCursed = (item: Item): boolean => item.cursed === true;
const isHighlyEnchanted = (item: Item): boolean =>
  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;

const surchargeRate = (item: Item): number =>
  (isCursed(item) ? CURSED_SURCHARGE_RATE : 0) +
  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE_RATE : 0);

const itemSurchargeAmount = (item: Item): number =>
  basePriceOf(item) * surchargeRate(item);

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const BLOCK_SIZE = 3;
const BLOCK_PRICE = 60;

const groupByType = (items: Item[]): Map<string, Item[]> =>
  items.reduce((groups, item) => {
    const existing = groups.get(item.type) ?? [];
    return groups.set(item.type, [...existing, item]);
  }, new Map<string, Item[]>());

const qualifiesForComponentBlock = (type: string, members: Item[]): boolean =>
  COMPONENT_TYPES.has(type) && members.length === BLOCK_SIZE;

const groupBasePremium = (type: string, members: Item[]): number => {
  if (qualifiesForComponentBlock(type, members)) return BLOCK_PRICE;
  return members.reduce((sum, item) => sum + basePriceOf(item), 0);
};

const itemsBaseSubtotal = (items: Item[]): number =>
  Array.from(groupByType(items)).reduce(
    (total, [type, members]) => total + groupBasePremium(type, members),
    0,
  );

const itemsSurchargeSubtotal = (items: Item[]): number =>
  items.reduce((sum, item) => sum + itemSurchargeAmount(item), 0);

const LOYALTY_DISCOUNT_RATE = 0.2;
const LOYALTY_YEARS_THRESHOLD = 2;

const isLoyalCustomer = (customer: Customer): boolean =>
  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;

const loyaltyDiscountRate = (customer: Customer): number =>
  isLoyalCustomer(customer) ? LOYALTY_DISCOUNT_RATE : 0;

const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
const FOLLOW_UP_DISCOUNT_RATE = 0.15;

const hasPreviousContract = (stepIndex: number): boolean => stepIndex > 0;

const followUpDiscountRate = (stepIndex: number): number =>
  hasPreviousContract(stepIndex) ? FOLLOW_UP_DISCOUNT_RATE : 0;

const policyAdjustmentRate = (customer: Customer, stepIndex: number): number =>
  FIRST_INSURANCE_SURCHARGE_RATE -
  loyaltyDiscountRate(customer) -
  followUpDiscountRate(stepIndex);

const quotePremium = (
  items: Item[],
  customer: Customer,
  stepIndex: number,
): number => {
  const baseSubtotal = itemsBaseSubtotal(items);
  const surchargeSubtotal = itemsSurchargeSubtotal(items);
  // Kept as `base + base*rate` (not `base*(1+rate)`) for IEEE-754 stability:
  // e.g. 100*(1+0.1) === 110.00000000000001, which trips Math.ceil rounding.
  return (
    baseSubtotal +
    baseSubtotal * policyAdjustmentRate(customer, stepIndex) +
    surchargeSubtotal +
    PROCESSING_FEE
  );
};

// MHPCO always rounds in its own favor: premiums up, payouts down.
const roundPremiumInMhpcoFavor = (amount: number): number => Math.ceil(amount);

const insuranceValueOf = (item: Item): number =>
  specOf(item)?.insuranceValue ?? 0;

const DEDUCTIBLE_PER_DAMAGE = 100;
const CAP_MULTIPLIER = 2;

const insuranceSum = (items: Item[]): number =>
  items.reduce((sum, item) => sum + insuranceValueOf(item), 0);

const damagePayout = (damage: Damage): number =>
  damage.amount - DEDUCTIBLE_PER_DAMAGE;

const runQuoteStep = (
  step: QuoteStep,
  customer: Customer,
  stepIndex: number,
): QuoteResult => ({
  premium: roundPremiumInMhpcoFavor(quotePremium(step.items, customer, stepIndex)),
});

const runClaimStep = (step: ClaimStep, policyItems: Item[]): ClaimResult => {
  const payout = step.incident.damages.reduce(
    (sum, damage) => sum + damagePayout(damage),
    0,
  );
  const cap = CAP_MULTIPLIER * insuranceSum(policyItems);
  return { payout, remainingCap: cap - payout };
};

const runStep = (
  step: Step,
  customer: Customer,
  stepIndex: number,
  steps: Step[],
): StepResult => {
  if (step.op === "quote") return runQuoteStep(step, customer, stepIndex);
  const policyStep = steps[step.policy] as QuoteStep;
  return runClaimStep(step, policyStep.items);
};

export const runScenario = (input: Scenario): ScenarioResult => ({
  results: input.steps.map((step, i) =>
    runStep(step, input.customer, i, input.steps),
  ),
});

import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // --- Simplest cases ---
  it("empty item list → premium 5 G (only the processing fee)", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(out.results[0]).toEqual({ premium: 5 });
  });

  // --- Base premiums for main items (each + 5 G fee) ---
  it("quote a plain sword → premium 115 G (100 base + 10 first-insurance + 5 fee)", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword" }] }],
    });
    expect(out.results[0]).toEqual({ premium: 115 });
  });
  it("quote a plain amulet → premium 71 G (60 base + 6 first-insurance + 5 fee)", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "amulet" }] }],
    });
    expect(out.results[0]).toEqual({ premium: 71 });
  });
  it("quote a plain staff → premium 93 G (80 base + 8 first-insurance + 5 fee)", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "staff" }] }],
    });
    expect(out.results[0]).toEqual({ premium: 93 });
  });
  it("quote a plain potion → premium 49 G (40 base + 4 first-insurance + 5 fee)", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "potion" }] }],
    });
    expect(out.results[0]).toEqual({ premium: 49 });
  });

  // --- Components and blocks ---
  it("quote 2 runes → 50 G base premium (50 + 5 first-insurance + 5 fee = 60)", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
    });
    expect(out.results[0]).toEqual({ premium: 60 });
  });
  it("quote 3 runes → 60 G base premium block (60 + 6 first-insurance + 5 fee = 71)", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }],
        },
      ],
    });
    expect(out.results[0]).toEqual({ premium: 71 });
  });
  it("quote 4 runes → 100 G base premium, no block (100 + 10 first-insurance + 5 fee = 115)", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
          ],
        },
      ],
    });
    expect(out.results[0]).toEqual({ premium: 115 });
  });
  it("quote 7 runes → 175 G base premium (175 + 17.5 first-insurance + 5 fee = 197.5 → rounds up to 198)", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: Array.from({ length: 7 }, () => ({ type: "rune" })),
        },
      ],
    });
    expect(out.results[0]).toEqual({ premium: 198 });
  });
  it("quote 2 runes + 1 moonstone → 75 G base premium (75 + 7.5 first-insurance + 5 fee = 87.5 → rounds up to 88)", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }],
        },
      ],
    });
    expect(out.results[0]).toEqual({ premium: 88 });
  });
  it("quote 3 runes + 3 moonstones → 120 G base premium (120 + 12 first-insurance + 5 fee = 137)", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
            { type: "moonstone" },
            { type: "moonstone" },
            { type: "moonstone" },
          ],
        },
      ],
    });
    expect(out.results[0]).toEqual({ premium: 137 });
  });

  // --- Item-specific modifiers ---
  it("cursed sword adds 50% surcharge on its base premium → 165 G (100 base + 50 curse + 10 first-insurance + 5 fee)", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", cursed: true }] }],
    });
    expect(out.results[0]).toEqual({ premium: 165 });
  });
  it("sword with enchantment 5 adds 30% surcharge → 145 G (100 base + 30 ench + 10 first-insurance + 5 fee)", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", enchantment: 5 }] }],
    });
    expect(out.results[0]).toEqual({ premium: 145 });
  });
  it("sword with enchantment 4 has no high-enchantment surcharge → 115 G (100 base + 10 first-insurance + 5 fee)", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", enchantment: 4 }] }],
    });
    expect(out.results[0]).toEqual({ premium: 115 });
  });
  it("cursed sword with enchantment 5 has both surcharges → 195 G (100 base + 50 curse + 30 ench + 10 first-insurance + 5 fee)", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", cursed: true, enchantment: 5 }],
        },
      ],
    });
    expect(out.results[0]).toEqual({ premium: 195 });
  });

  // --- Policy-wide modifiers ---
  it("long-standing customer (≥ 2 years) gets 20% loyalty discount on policy base", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 3 },
      steps: [{ op: "quote", items: [{ type: "sword" }] }],
    });
    expect(out.results[0]).toEqual({ premium: 95 });
  });
  it("customer with exactly 2 years gets loyalty discount", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 2 },
      steps: [{ op: "quote", items: [{ type: "sword" }] }],
    });
    expect(out.results[0]).toEqual({ premium: 95 });
  });
  it("first insurance carries 10% initial assessment surcharge on policy base", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword" }] }],
    });
    expect(out.results[0]).toEqual({ premium: 115 });
  });
  it("second contract gets 15% follow-up discount on policy base", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "sword" }] },
        { op: "quote", items: [{ type: "sword" }] },
      ],
    });
    expect(out.results[1]).toEqual({ premium: 100 });
  });

  // --- Modifier scope on multi-item policies ---
  it("cursed sword + plain amulet → curse on sword only (160 + 50 + 16 first-insurance + 5 fee = 231 G)", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "sword", cursed: true },
            { type: "amulet" },
          ],
        },
      ],
    });
    expect(out.results[0]).toEqual({ premium: 231 });
  });

  // --- Rounding ---
  it("premium yielding 197.5 G rounds up to 198 G (MHPCO favor)", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: Array.from({ length: 7 }, () => ({ type: "rune" })),
        },
      ],
    });
    expect(out.results[0]).toEqual({ premium: 198 });
  });

  // --- Integration examples ---
  it("newcomer with cursed sword (0 years, no prev contract, ench 3) → 165 G", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", cursed: true, enchantment: 3 }],
        },
      ],
    });
    expect(out.results[0]).toEqual({ premium: 165 });
  });
  it("long-standing customer's second cursed enchanted sword (3 yrs, ench 7) → 160 G", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 3 },
      steps: [
        { op: "quote", items: [{ type: "amulet" }] },
        {
          op: "quote",
          items: [{ type: "sword", cursed: true, enchantment: 7 }],
        },
      ],
    });
    expect(out.results[1]).toEqual({ premium: 160 });
  });

  // --- Claim: basic standard reimbursement ---
  it("regular sword damage 500 G → payout 400 G (500 − 100 deductible)", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "sword" }] },
        {
          op: "claim",
          policy: 0,
          incident: {
            cause: "fire",
            damages: [{ itemType: "sword", amount: 500 }],
          },
        },
      ],
    });
    expect(out.results[1]).toEqual({ payout: 400, remainingCap: 1600 });
  });
  it.todo("rune damage 200 G → payout 100 G (no special clause)");

  // --- Claim: special clauses ---
