  reimbursableAmount(damage, item) - DEDUCTIBLE_PER_DAMAGE;

// The CLI rejects claims for items not on the policy upstream, so the lookup
// is total over the inputs that reach this function.
const policyItemOfType = (policyItems: Item[], itemType: string): Item =>
  policyItems.find((item) => item.type === itemType) as Item;

const totalPayout = (damages: Damage[], policyItems: Item[]): number =>
  damages.reduce(
    (sum, damage) =>
      sum + damagePayout(damage, policyItemOfType(policyItems, damage.itemType)),
    0,
  );

const policyCap = (policyItems: Item[]): number =>
  CAP_MULTIPLIER * insuranceSum(policyItems);

const runQuoteStep = (
  step: QuoteStep,
  customer: Customer,
  stepIndex: number,
): QuoteResult => ({
  premium: roundPremiumInMhpcoFavor(quotePremium(step.items, customer, stepIndex)),
});

const runClaimStep = (step: ClaimStep, policyItems: Item[]): ClaimResult => {
  const payout = totalPayout(step.incident.damages, policyItems);
  return { payout, remainingCap: policyCap(policyItems) - payout };
};

// Claim steps reference a prior quote step by index; the CLI guarantees that
// reference is valid and points at a quote, so the lookup is total.
const policyItemsAt = (steps: Step[], policyIndex: number): Item[] =>
  (steps[policyIndex] as QuoteStep).items;

const runStep = (
  step: Step,
  customer: Customer,
  stepIndex: number,
  steps: Step[],
): StepResult =>
  step.op === "quote"
    ? runQuoteStep(step, customer, stepIndex)
    : runClaimStep(step, policyItemsAt(steps, step.policy));

export const runScenario = (input: Scenario): ScenarioResult => ({
  results: input.steps.map((step, i) =>
    runStep(step, input.customer, i, input.steps),
  ),
});

