const runClaimStep = (
  step: ClaimStep,
  policyItems: Item[],
  availableCap: number,
): ClaimResult => {
  const requested = roundPayoutInMhpcoFavor(
    totalPayout(step.incident.damages, policyItems),
  );
  const payout = Math.min(requested, availableCap);
  return { payout, remainingCap: availableCap - payout };
};

