const countByType = (entries: { type?: string; itemType?: string }[]): Map<string, number> => {
  const counts = new Map<string, number>();
  for (const entry of entries) {
    const key = (entry.type ?? entry.itemType) as string;
    counts.set(key, (counts.get(key) ?? 0) + 1);
  }
  return counts;
};

const validateDamagesAgainstPolicy = (
  damages: Damage[],
  policyItems: Item[],
): void => {
  const policyCounts = countByType(policyItems);
  const damageCounts = countByType(damages);
  for (const [itemType, damageCount] of damageCounts) {
    const policyCount = policyCounts.get(itemType) ?? 0;
    if (damageCount > policyCount) {
      throw new Error(
        `claim references more '${itemType}' damages (${damageCount}) than the policy covers (${policyCount})`,
      );
    }
  }
};

const settleClaimAgainstPolicyCap = (
  step: ClaimStep,
  steps: Step[],
  remainingCaps: Map<number, number>,
): ClaimResult => {
  const policyItems = policyItemsAt(steps, step.policy);
  validateDamagesAgainstPolicy(step.incident.damages, policyItems);
  const availableCap = remainingCaps.get(step.policy) ?? policyCap(policyItems);
  const result = settleClaim(step, policyItems, availableCap);
  remainingCaps.set(step.policy, result.remainingCap);
  return result;
};

